#include <vector>
#include <climits>
#include <algorithm>

using namespace std;

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    // Directions: right (0, 1), down (1, 0)
    vector<pair<int, int>> directions = {{0, 1}, {1, 0}};

    // Initialize a 2D array to store the minimum cost to reach each cell
    vector<vector<long long>> dp(m, vector<long long>(n, LONG_MAX));

    // Starting point: (0, 0)
    dp[0][0] = (0 + 1) * (0 + 1); // Entry cost at (0, 0)

    // Priority queue for Dijkstra's algorithm
    // Each element is a tuple (total_cost, time, i, j)
    priority_queue<pair<long long, pair<int, pair<int, int>>>> pq;
    pq.push({dp[0][0], 1, 0, 0});

    while (!pq.empty()) {
        long long total_cost = pq.top().first;
        int time = pq.top().second.first;
        int i = pq.top().third.first;
        int j = pq.top().third.second;
        pq.pop();

        // If we have already found a better path to this cell, skip
        if (total_cost > dp[i][j]) {
            continue;
        }

        // If we reached the destination, return the total cost
        if (i == m - 1 && j == n - 1) {
            return total_cost;
        }

        // Move to the next cell (either right or down)
        for (auto& dir : directions) {
            int ni = i + dir.first;
            int nj = j + dir.second;

            // Check if the new cell is within bounds
            if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                long long new_cost = total_cost + (ni + 1) * (nj + 1);
                long long new_time = time + 1;

                // If the new time is odd, it's a move step (no wait cost)
                if (new_time % 2 == 1) {
                    if (new_cost < dp[ni][nj]) {
                        dp[ni][nj] = new_cost;
                        pq.push({new_cost, new_time, ni, nj});
                    }
                } else {
                    // If the new time is even, it's a wait step
                    long long wait_cost = waitCost[ni][nj];
                    long long new_total_cost = new_cost + wait_cost;
                    if (new_total_cost < dp[ni][nj]) {
                        dp[ni][nj] = new_total_cost;
                        pq.push({new_total_cost, new_time, ni, nj});
                    }
                }
            }
        }
    }

    // If no path is found (should not happen in valid inputs)
    return -1;
}

