fun solve(m: Long, n: Long, waitCost: Array<Array<Long>>): Long {
    val directions = arrayOf(intArrayOf(0, 1), intArrayOf(1, 0))
    val dp = Array(m){ Array(n){ Long.MAX_VALUE } }
    dp[0][0] = (0 + 1) * (0 + 1)

    import java.util.*
    val pq = PriorityQueue<Triple<Long, Int, Int, Int>>(Comparator { a, b -> a.first.compareTo(b.first) })
    pq.add(Triple(dp[0][0], 1, 0, 0))

    while (pq.isNotEmpty()) {
        val (totalCost, time, i, j) = pq.poll()
        if (totalCost > dp[i][j]) continue
        if (i == m - 1 && j == n - 1) return totalCost

        for (dir in directions) {
            val ni = i + dir[0]
            val nj = j + dir[1]
            if (ni in 0..m-1 && nj in 0..n-1) {
                val newCost = totalCost + (ni + 1) * (nj + 1)
                val newTime = time + 1

                if (newTime % 2 == 1) {
                    if (newCost < dp[ni][nj]) {
                        dp[ni][nj] = newCost
                        pq.add(Triple(newCost, newTime, ni, nj))
                    }
                } else {
                    val waitCostVal = waitCost[ni][nj]
                    val newTotalCost = newCost + waitCostVal
                    if (newTotalCost < dp[ni][nj]) {
                        dp[ni][nj] = newTotalCost
                        pq.add(Triple(newTotalCost, newTime, ni, nj))
                    }
                }
            }
        }
    }

    return -1
}
